import{_ as i,o as t,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"86. Classification And Reclassification","description":"","frontmatter":{"title":"86. Classification And Reclassification","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/86-classification-and-reclassification.md","filePath":"ebas/allied-health/classification-staffing/86-classification-and-reclassification.md"}'),o={name:"ebas/allied-health/classification-staffing/86-classification-and-reclassification.md"};function r(n,e,l,c,h,d){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_86-classification-and-reclassification" tabindex="-1">86. Classification And Reclassification <a class="header-anchor" href="#_86-classification-and-reclassification" aria-label="Permalink to &quot;86. Classification And Reclassification&quot;">​</a></h1><p><strong>86.1</strong> All Employees will be paid the applicable rate of pay for their grade and classification as set out in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> (Wage Rates).</p><p><strong>86.2</strong> The grades and classifications of all Employees (including a reclassification request) will be determined in accordance with the classification definitions in performed, eligibility, levels of responsibility, skill and experience for the classifications under this Agreement. An Employee’s classification is not determined by the Employee’s performance in the position or the staffing profile in the area/department.</p><p><strong>86.3</strong> Employers will, in the Employee’s letter of offer, advise the Employee in writing of their classification under this Agreement as per <a href="/eba/ebas/allied-health/employment/23-letter-of-offer.html">clause 23</a> (Letter of Offer).</p><p><strong>86.4</strong> Where the Employee’s classification changes, the Employer will confirm the change in writing as soon as possible.</p><p><strong>86.5</strong> Where an Employee believes that the work performed and required by their position is better described by another classification with a higher rate of pay, the Employee may seek reclassification by notifying the Employer in writing, addressing why they believe another classification better describes the work performed and required by their position, having regard to both the current and proposed classification. The Employee’s Manager may also make the reclassification request.</p><p><strong>86.6</strong> The Employer will provide a written response to the requested reclassification within four (4) weeks. Where the Employer, in accordance with subclause 86.2, does not believe the work performed and required by the Employee’s position is better described by another classification, the Employer will provide the reasons for this, having regard to both the current and proposed classification.</p><p><strong>86.7</strong> Where the Employer determines, in accordance with subclause 86.5 and 86.6, that another classification better describes the work performed and required by the Employee’s position, the reclassification will take effect from the earlier of:</p><p><strong>(a)</strong> where it can reasonably be determined, the date on which the Employee’s work was better described by another classification; or</p><p><strong>(b)</strong> the date the written reclassification request was submitted.</p><p><strong>86.8</strong> At any time, either the Employee or Employer may refer a request for reclassification to the dispute settlement procedure in <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of this Agreement.</p><p><strong>86.9</strong> Reclassification will occur on the basis of the overall work performed and required by the Employee’s position, subject to the classifications.</p><p><strong>86.10</strong> Where an Employer is aware an Employee is performing work that is not required by their position and does not advise the Employee the work is not required, this work is deemed to be work required by the Employee’s position.</p>',13)])])}const m=i(o,[["render",r]]);export{f as __pageData,m as default};
